100: func NewQueryParams(opts ...QueryOption) (params QueryParams) {
101: 	for _, opt := range opts {
102: 		opt(&params)
103: 	}
104: 
105: 	// NOTE(georgemac): I wanted to normalize under all circumstances
106: 	// However, for legacy reasons the core flag state APIs expect
107: 	// the default limit to be == 0. Normalize sets it to the default
108: 	// constant which is > 0.
109: 	// If we ever break this contract then we can normalize here.
110: 	// params.Normalize()
111: 
112: 	return params
113: }
