346: // Reference is a string which can refer to either a concrete
347: // revision or it can be an indirect named reference.
348: type Reference string
349: 
350: // ReferenceRequest is used to identify a request predicated solely by a revision reference.
351: // This is primarily used for namespaces as it is the highest level domain model.
352: type ReferenceRequest struct {
353: 	Reference
354: }
355: 
356: // WithReference sets the provided reference identifier on a *ReferenceRequest.
357: func WithReference(ref string) containers.Option[ReferenceRequest] {
358: 	return func(rp *ReferenceRequest) {
359: 		if ref != "" {
360: 			rp.Reference = Reference(ref)
361: 		}
362: 	}
363: }
364: 
365: // ListWithReference is a ListOption constrained to ReferenceRequest types.
366: // It sets the reference on the resulting list request.
367: func ListWithReference(ref string) ListOption[ReferenceRequest] {
368: 	return func(rp *ListRequest[ReferenceRequest]) {
369: 		if ref != "" {
370: 			rp.Predicate.Reference = Reference(ref)
371: 		}
372: 	}
373: }
